const unsigned pueo1_num_runs = 620;

inline int pueo1_find_run(int t)
{
  pueo1_runinfo dummy ( 0,t,t,0);
  auto idx = std::upper_bound(pueo1_flight, pueo1_flight + pueo1_num_runs, dummy) - pueo1_flight;
  if (idx >= pueo1_num_runs)
  {
    return -1;
  }
  if (idx == 0 && t < pueo1_flight[0].start_time) return -1;
  return idx;
}


